// ---- shared content helpers (one copy each) -------------------------------
function fmt(n) { try { return n.toLocaleString(); } catch (e) { return "" + n; } }
function fmtN(n) { try { return n.toLocaleString(); } catch (e) { return "" + n; } }
function clickRect(g, x, y, w, h, onClick) {
  var r = rect(x, y, w, h, 4, "#ffffff"); r.setAttribute("opacity", "0"); r.style.cursor = "pointer";
  r.addEventListener("click", onClick); g.appendChild(r);
}
// author verification tag: 0 None (no tag) · 1 Identity · 2 Residency · 3 Official (MLA / gov)
function tierLabel(t) { return ["", "Identity", "Residency", "Official"][t] || ""; }
function hasReactions(p) { return p.type === "statement" || p.type === "result"; }
var FEED_TYPE_NAME = { statement: "Statements", petition: "Petitions", poll: "Polls", result: "Results" };

// geography (districts is a list: [] jurisdiction-wide · [slug…] specific ridings)
var MY_DISTRICTS = ["edmonton-strathcona"]; // the example signed-in resident's home riding(s)
function postDistricts(p) { return p.districts || []; }
function inMyDistricts(p) { return postDistricts(p).some(function (s) { return MY_DISTRICTS.indexOf(s) >= 0; }); }
function districtTag(p) {
  var ds = postDistricts(p);
  if (!ds.length) return "";
  return ds.length === 1 ? districtName(ds[0]) : (districtName(ds[0]) + " +" + (ds.length - 1));
}

// count scaling: shown counts shrink as the Verified filter rises (fewer qualifying voices).
// social = comments + agree/disagree reactions (drop at every level).
// civic  = petition signatures + poll votes — only drop at Official, since Alberta participation
//          already requires residency verification (ID/Residency filters don't thin them).
var SOCIAL_SCALE = [1, 0.62, 0.34, 0.08];
var CIVIC_SCALE  = [1, 1, 1, 0.12];
function scaleSocial(n) { return Math.max(0, Math.round(n * SOCIAL_SCALE[state.verified])); }
function scaleCivic(n)  { return Math.max(0, Math.round(n * CIVIC_SCALE[state.verified])); }

// initials from a name: first word + last word, with any ", MLA"-style suffix stripped
function initials(name) {
  var base = name.split(",")[0].trim().split(/\s+/);
  var f = base[0] || "", l = base[base.length - 1] || "";
  return ((f[0] || "") + (l[0] || "")).toUpperCase();
}
// right-aligned leader link: a small initials avatar + the name, ending at rightX
function leaderLink(parent, rightX, baselineY, name, nameSize, onClick) {
  var nameW = name.length * (nameSize * 0.54), nameStartX = rightX - nameW;
  var avCx = nameStartX - 15, avCy = baselineY - 4, r = 11;
  var g = document.createElementNS(SVG_NS, "g"); g.style.cursor = "pointer";
  var av = document.createElementNS(SVG_NS, "circle");
  av.setAttribute("cx", avCx); av.setAttribute("cy", avCy); av.setAttribute("r", r);
  av.setAttribute("fill", "#e8e8e8"); av.setAttribute("stroke", "#ccc"); g.appendChild(av);
  var it = txt(avCx, avCy + 3, initials(name), 9, "#777"); it.setAttribute("text-anchor", "middle"); g.appendChild(it);
  var nt = txt(rightX, baselineY, name, nameSize, "#333"); nt.setAttribute("text-anchor", "end"); g.appendChild(nt);
  clickRect(g, avCx - r - 4, baselineY - 18, rightX - (avCx - r - 4), 26, onClick);
  parent.appendChild(g);
}
// right-aligned scope tag — "<Jurisdiction> · <District>" with each word deep-linking to its
// page (jurisdiction → Jurisdiction view · district → District view). Either part may be empty
// when the page already names it. Renders the text exactly as before, then lays invisible hit
// targets over each word (widths estimated, right-anchored). Returns the <g> to layer on top.
function scopeTagLink(jurName, districtLabel, rightX, baselineY) {
  var g = document.createElementNS(SVG_NS, "g"); g.style.cursor = "pointer";
  var size = 11.5, cw = size * 0.55, sep = (jurName && districtLabel) ? " · " : "";
  var segs = [];
  if (jurName) segs.push([jurName, true]);
  if (sep) segs.push([sep, false]);
  if (districtLabel) segs.push([districtLabel, true]);
  var t = txtSeg(rightX, baselineY, size, "#999", segs);
  t.setAttribute("text-anchor", "end"); g.appendChild(t);
  var top = baselineY - 12, h = 17;
  if (districtLabel) { var dw = districtLabel.length * cw; clickRect(g, rightX - dw, top, dw + 4, h, go("district")); }
  if (jurName) { var off = (districtLabel.length + sep.length) * cw, jw = jurName.length * cw; clickRect(g, rightX - off - jw, top, jw + 2, h, goJur(jurName)); }
  return g;
}
// a collapsible section header — leading icon, label, chevron on the RIGHT. Returns y below it.
function collHeader(parent, x, w, y, iconHref, label, open, countText, onToggle) {
  var g = document.createElementNS(SVG_NS, "g"); g.style.cursor = "pointer";
  g.appendChild(rect(x, y, w, 38, 8, "#f7f7f7", "#e2e2e2"));
  g.appendChild(icon(iconHref, x + 12, y + 11, 16, "#333"));
  var t = txt(x + 38, y + 24, label, 14, "#333"); t.setAttribute("font-weight", "bold"); g.appendChild(t);
  g.appendChild(icon(open ? "#ic-chevron" : "#ic-chevron-right", x + w - 26, y + 11, 16, "#666"));
  if (countText) { var c = txt(x + w - 34, y + 24, countText, 12, "#999"); c.setAttribute("text-anchor", "end"); g.appendChild(c); }
  g.addEventListener("click", onToggle);
  parent.appendChild(g);
  return y + 38;
}
// pretend map vector: light landmass with a red translucent region (jurisdiction or riding)
function poly(pts, x, y) { return "M" + pts.map(function (p) { return (x + p[0]) + "," + (y + p[1]); }).join(" L ") + " Z"; }
function pathEl(d, fill, stroke, sw, op) {
  var p = document.createElementNS(SVG_NS, "path");
  p.setAttribute("d", d); p.setAttribute("fill", fill);
  if (stroke) { p.setAttribute("stroke", stroke); p.setAttribute("stroke-width", sw || 1.5); }
  if (op != null) p.setAttribute("fill-opacity", op);
  p.setAttribute("stroke-linejoin", "round"); return p;
}
function drawMapVector(parent, x, y, w, h, label) {
  parent.appendChild(rect(x, y, w, h, 10, "#eef2f4", "#dfe5e8"));
  var land = [[16,86],[54,52],[110,64],[150,40],[214,52],[276,40],[330,60],[352,96],[330,140],[268,156],[196,146],[122,156],[58,142],[26,118]];
  parent.appendChild(pathEl(poly(land, x, y), "#e3e6e3", "#cdd2cd", 1.4, null));
  var bl = document.createElementNS(SVG_NS, "path");
  bl.setAttribute("d", "M" + (x + 196) + "," + (y + 50) + " L" + (x + 196) + "," + (y + 150));
  bl.setAttribute("stroke", "#d3d8d3"); bl.setAttribute("fill", "none"); bl.setAttribute("stroke-dasharray", "3 3"); parent.appendChild(bl);
  var prov = [[120,70],[176,66],[190,150],[128,156]];
  parent.appendChild(pathEl(poly(prov, x, y), "#e74c3c", "#c0392b", 1.6, 0.32));
  parent.appendChild(icon("#ic-pin", x + 150 - 9, y + 92, 18, "#c0392b"));
  var lb = txt(x + 154, y + 128, label, 11, "#c0392b"); lb.setAttribute("font-weight", "bold"); parent.appendChild(lb);
}
function drawDistrictMap(parent, x, y, w, h, label) {
  parent.appendChild(rect(x, y, w, h, 10, "#eef2f4", "#dfe5e8"));
  var land = [[16,86],[54,52],[110,64],[150,40],[214,52],[276,40],[330,60],[352,96],[330,140],[268,156],[196,146],[122,156],[58,142],[26,118]];
  parent.appendChild(pathEl(poly(land, x, y), "#e3e6e3", "#cdd2cd", 1.4, null));
  var riding = [[150,74],[196,68],[206,104],[158,112]];
  parent.appendChild(pathEl(poly(riding, x, y), "#e74c3c", "#c0392b", 1.6, 0.32));
  parent.appendChild(icon("#ic-pin", x + 178 - 9, y + 80, 18, "#c0392b"));
  var lb = txt(x + 150, y + 134, label, 11, "#c0392b"); lb.setAttribute("font-weight", "bold"); parent.appendChild(lb);
}

// ============================================================================
// THE FILTER MATRIX — one matcher for all three scopes (replaces the three
// drifted feedMatches / jurFeedMatches / distFeedMatches). Record-type include
// and the Verified ladder (p.tier >= state.verified, inclusive-upward) apply
// everywhere; the scope decides the jurisdiction/geography test.
//   feed         : subscribed-jurisdiction include + My Districts (keep all Global
//                  + only your ridings of subscribed jurisdictions)
//   jurisdiction : limited to state.jur (+ My Districts limits to your ridings)
//   district     : limited to posts that apply to DISTRICT.slug (incl. multi-district)
// ============================================================================
function matches(p, scope) {
  var rt = state.recordTypes.filter(function (r) { return r.name === FEED_TYPE_NAME[p.type]; })[0];
  if (!rt || !rt.included) return false;        // record-type include (all scopes)
  if (p.tier < state.verified) return false;    // min author verification (all scopes)
  if (scope === "feed") {
    var sub = subByName(p.jur);
    if (!sub || !sub.included) return false;    // unified-feed jurisdiction filter
    if (state.myDistricts && p.jur !== "Global" && !inMyDistricts(p)) return false;
    return true;
  }
  if (scope === "jurisdiction") {
    if (p.jur !== state.jur) return false;
    if (state.myDistricts && !inMyDistricts(p)) return false;
    return true;
  }
  if (scope === "district") {
    return postDistricts(p).indexOf(DISTRICT.slug) >= 0;
  }
  return false;
}

// build one card; returns a <g> with a ._h height property the caller stacks by.
// opts.hideJur / opts.hideDistrict drop the redundant tag parts the page already implies.
// Click targets are LIVE page-flips: author → Profile, title/…more → Post.
function buildCard(p, opts) {
  opts = opts || {};
  var W = 370, px = 16;
  var g = document.createElementNS(SVG_NS, "g");
  var kids = [], hits = [];
  function add(n) { kids.push(n); return n; }
  function hit(n) { hits.push(n); return n; }

  // author row
  var av = document.createElementNS(SVG_NS, "circle");
  av.setAttribute("cx", px + 14); av.setAttribute("cy", 26); av.setAttribute("r", 14);
  av.setAttribute("fill", "#e8e8e8"); av.setAttribute("stroke", "#ccc"); add(av);
  var ini = (p.author.split(" ").map(function (s) { return s[0]; }).join("")).slice(0, 2).toUpperCase();
  var it = txt(px + 14, 30, ini, 11, "#777"); it.setAttribute("text-anchor", "middle"); add(it);
  var nm = txt(px + 38, 22, p.author, 13.5, "#333"); nm.setAttribute("font-weight", "bold"); add(nm);
  add(txt(px + 38, 37, "@" + p.handle, 11.5, "#999"));
  var aHit = document.createElementNS(SVG_NS, "g"); clickRect(aHit, 0, 8, 190, 34, go("profile")); hit(aHit);
  // verification tier + jurisdiction/district tag
  if (p.tier > 0) {
    add(icon("#ic-shield", W - px - 88, 13, 14, "#666"));
    var tl = txt(W - px, 24, tierLabel(p.tier), 11.5, "#666"); tl.setAttribute("text-anchor", "end"); add(tl);
  }
  var jurName = opts.hideJur ? "" : p.jur;
  var distLabel = opts.hideDistrict ? "" : districtTag(p);
  if (jurName || distLabel) hit(scopeTagLink(jurName, distLabel, W - px, 38));

  // title (tap → post)
  var ti = txt(px, 66, p.title, 15, "#222"); ti.setAttribute("font-weight", "bold"); add(ti);
  add(txt(px, 90, p.body[0], 12.5, "#777"));
  add(txt(px, 108, p.body[1] || "", 12.5, "#777"));
  var more = txt(px, 130, "…more", 12.5, "#333"); more.setAttribute("font-weight", "bold"); add(more);
  var postHit = document.createElementNS(SVG_NS, "g");
  clickRect(postHit, px - 4, 54, W - 2 * px + 8, 22, go("post")); // title row
  clickRect(postHit, px - 4, 120, 80, 18, go("post"));            // …more
  hit(postHit);

  // type-specific section
  var y = 150;
  if (p.type === "petition") {
    var sig = scaleCivic(p.sig);
    var frac = clamp(sig / p.goal, 0, 1);
    add(rect(px, y + 2, W - 2 * px, 10, 5, "#f2f2f2", "#ccc"));
    add(rect(px, y + 2, Math.round((W - 2 * px) * frac), 10, 5, "#333"));
    add(txt(px, y + 32, fmt(sig) + " / " + fmt(p.goal) + " signatures", 12, "#555"));
    var cta = rect(px, y + 44, 150, 26, 13, "#ffffff", "#333"); add(cta);
    var ct = txt(px + 75, y + 61, "Sign the Petition", 12.5, "#333"); ct.setAttribute("text-anchor", "middle"); add(ct);
    y += 84;
  } else if (p.type === "poll") {
    var total = p.options.reduce(function (a, o) { return a + o.v; }, 0) || 1;
    p.options.forEach(function (o) {
      var ov = scaleCivic(o.v), bw = W - 2 * px;
      add(rect(px, y, bw, 18, 4, "#f4f4f4", "#e2e2e2"));
      add(rect(px, y, Math.round(bw * (o.v / total)), 18, 4, "#e3e3e3"));
      add(txt(px + 8, y + 13, o.label, 11.5, "#555"));
      var pv = txt(W - px - 6, y + 13, fmt(ov), 11.5, "#777"); pv.setAttribute("text-anchor", "end"); add(pv);
      y += 24;
    });
    y += 4;
  } else if (p.type === "result") {
    add(rect(px, y, W - 2 * px, 28, 6, "#f7f7f7", "#ddd"));
    add(icon("#ic-check-circle", px + 8, y + 6, 16, "#555"));
    add(txt(px + 32, y + 19, p.outcome, 12.5, "#444"));
    y += 38;
  }

  // footer: reactions (where applicable) + comments
  var fy = y + 14;
  if (hasReactions(p)) {
    // same reactBtn the post page uses — clickable, login-gated, thinned by the Verified filter.
    // collected in a hit group so the buttons sit above the card background (added below kids).
    var rg = document.createElementNS(SVG_NS, "g");
    reactBtn(rg, p, "up", px, fy, scaleSocial);
    reactBtn(rg, p, "down", px + 66, fy, scaleSocial);
    hit(rg);
  } else if (p.type === "poll") {
    var tv = p.options.reduce(function (a, o) { return a + scaleCivic(o.v); }, 0);
    add(txt(px, fy, fmt(tv) + " votes", 13, "#555"));
  } else {
    add(txt(px, fy, fmt(scaleCivic(p.sig)) + " signatures", 13, "#555"));
  }
  add(icon("#ic-message", W - px - 64, fy - 13, 15, "#777"));
  var cc = txt(W - px, fy, fmt(scaleSocial(p.comments)), 13, "#777"); cc.setAttribute("text-anchor", "end"); add(cc);

  var cardH = fy + 16;
  g.appendChild(rect(0, 0, W, cardH, 12, "#ffffff", "#ccc"));
  kids.forEach(function (n) { g.appendChild(n); });
  hits.forEach(function (n) { g.appendChild(n); });
  g._h = cardH;
  return g;
}

// ============================================================================
// VIEW BUILDERS — each clears its body, lays out content top-down, and calls
// setViewScroll(key, y) to compute the view's scroll max (with FOOTER_PAD) and
// apply the scroll transform. One card renderer (buildCard) + one matcher
// (matches) feed all three list views.
// ============================================================================

// ---- FEED -----------------------------------------------------------------
function buildFeed() {
  var body = $("vFeedBody");
  while (body.firstChild) body.removeChild(body.firstChild);
  var X = 30, y = 124, GAP = 14;
  // single jurisdiction selected ⇒ the selector already names it, so drop the jur tag on cards
  var single = state.subs.filter(function (s) { return s.included; }).length === 1;
  var shown = POSTS.filter(function (p) { return matches(p, "feed"); });
  if (shown.length === 0) {
    var e1 = txt(215, 320, "No posts match the current filter.", 14, "#999");
    e1.setAttribute("text-anchor", "middle"); body.appendChild(e1);
    var e2 = txt(215, 344, "Adjust record types · jurisdictions · Refine (F).", 12, "#bbb");
    e2.setAttribute("text-anchor", "middle"); body.appendChild(e2);
  }
  shown.forEach(function (p) {
    var card = buildCard(p, { hideJur: single });
    card.setAttribute("transform", "translate(" + X + "," + y + ")");
    body.appendChild(card);
    y += card._h + GAP;
  });
  setViewScroll("feed", y);
}

// ---- JURISDICTION ---------------------------------------------------------
function buildJurisdiction() {
  var body = $("vJurBody");
  while (body.firstChild) body.removeChild(body.firstChild);
  var X = 30, W = 370, d = JUR_DATA[state.jur], y = 124;

  // title bar: name (left) + leader profile link (right)
  var nm = txt(X, y + 26, state.jur, 22, "#222"); nm.setAttribute("font-weight", "bold"); body.appendChild(nm);
  leaderLink(body, X + W - 2, y + 22, d.leader.name, 12.5, go("profile"));
  y += 50;

  // Map (collapsible; hidden for Global)
  if (state.jur !== "Global") {
    y = collHeader(body, X, W, y, "#ic-pin", "Map", state.jurMapOpen, null, function () { state.jurMapOpen = !state.jurMapOpen; render(); });
    if (state.jurMapOpen) { y += 8; drawMapVector(body, X, y, W, 176, state.jur); y += 176 + 8; }
    else { y += 12; }
  }

  // Rules (collapsible)
  y = collHeader(body, X, W, y, "#ic-file", "Rules", state.jurRulesOpen, null, function () { state.jurRulesOpen = !state.jurRulesOpen; render(); });
  if (state.jurRulesOpen) {
    y += 8;
    d.rules.forEach(function (line) {
      body.appendChild(txt(X + 14, y + 12, "•", 13, "#999"));
      body.appendChild(txt(X + 30, y + 12, line, 12.5, "#555"));
      y += 22;
    });
    y += 8;
  } else { y += 12; }

  // Districts / Ridings (collapsible; hidden when the jurisdiction has none)
  if (d.districts.length) {
    y = collHeader(body, X, W, y, "#ic-list", d.districtLabel, state.jurDistrictsOpen,
      d.districts.length + " " + d.districtLabel.toLowerCase(),
      function () { state.jurDistrictsOpen = !state.jurDistrictsOpen; render(); });
    if (state.jurDistrictsOpen) {
      y += 8;
      d.districts.forEach(function (dr) {
        var rowY = y, row = document.createElementNS(SVG_NS, "g");
        row.appendChild(rect(X, rowY, W, 44, 8, "#ffffff", "#eee"));
        var rn = txt(X + 14, rowY + 27, dr.name, 13.5, "#333"); rn.setAttribute("font-weight", "bold"); row.appendChild(rn);
        clickRect(row, X, rowY, W, 44, go("district"));            // name/body → District view
        leaderLink(row, X + W - 12, rowY + 27, dr.leader, 11.5, go("profile")); // → Profile (on top)
        body.appendChild(row);
        y += 50;
      });
      y += 4;
    } else { y += 12; }
  }

  // Jurisdiction Feed (collapsible, collapsed by default; inline, pre-filtered cards)
  var shown = POSTS.filter(function (p) { return matches(p, "jurisdiction"); });
  y = collHeader(body, X, W, y, "#ic-newspaper", "Jurisdiction Feed", state.jurFeedOpen, shown.length + " posts",
    function () { state.jurFeedOpen = !state.jurFeedOpen; render(); });
  if (state.jurFeedOpen) {
    y += 10;
    body.appendChild(txt(X + 2, y, "Pre-filtered to " + state.jur + " — record type & Refine (F) still apply.", 10.5, "#bbb"));
    y += 16;
    if (shown.length === 0) {
      var e1 = txt(X + W / 2, y + 18, "No posts match the current filter.", 13, "#999"); e1.setAttribute("text-anchor", "middle"); body.appendChild(e1);
      y += 44;
    }
    shown.forEach(function (p) {
      var card = buildCard(p, { hideJur: true }); // scoped to this jurisdiction → drop the jur tag
      card.setAttribute("transform", "translate(" + X + "," + y + ")");
      body.appendChild(card);
      y += card._h + 14;
    });
  } else { y += 12; }

  setViewScroll("jurisdiction", y);
}

// ---- DISTRICT -------------------------------------------------------------
function buildDistrict() {
  var body = $("vDistBody");
  while (body.firstChild) body.removeChild(body.firstChild);
  var X = 30, W = 370, d = DISTRICT, y = 124;

  // title bar: riding name + parent line (left) + leader profile link (right)
  var nm = txt(X, y + 24, d.name, 19, "#222"); nm.setAttribute("font-weight", "bold"); body.appendChild(nm);
  body.appendChild(txtSeg(X, y + 42, 11.5, "#999", [[d.jur, true], [" · riding · boundary " + d.boundaryYear, false]]));
  var djg = document.createElementNS(SVG_NS, "g"); // parent jurisdiction word → Jurisdiction view
  clickRect(djg, X - 2, y + 30, d.jur.length * 11.5 * 0.55 + 4, 16, goJur(d.jur)); body.appendChild(djg);
  leaderLink(body, X + W - 2, y + 20, d.leader, 12.5, go("profile"));
  y += 56;

  // Map (collapsible) — this riding highlighted within the province
  y = collHeader(body, X, W, y, "#ic-pin", "Map", state.distMapOpen, null, function () { state.distMapOpen = !state.distMapOpen; render(); });
  if (state.distMapOpen) { y += 8; drawDistrictMap(body, X, y, W, 176, d.name); y += 176 + 8; }
  else { y += 12; }

  // About this riding (collapsible)
  y = collHeader(body, X, W, y, "#ic-file", "About this riding", state.distAboutOpen, null,
    function () { state.distAboutOpen = !state.distAboutOpen; render(); });
  if (state.distAboutOpen) {
    y += 8;
    d.about.forEach(function (line) {
      body.appendChild(txt(X + 14, y + 12, "•", 13, "#999"));
      body.appendChild(txt(X + 30, y + 12, line, 12.5, "#555"));
      y += 22;
    });
    y += 8;
  } else { y += 12; }

  // District Feed (collapsible, collapsed by default; inline, pre-filtered cards)
  var shown = POSTS.filter(function (p) { return matches(p, "district"); });
  y = collHeader(body, X, W, y, "#ic-newspaper", "District Feed", state.distFeedOpen, shown.length + " posts",
    function () { state.distFeedOpen = !state.distFeedOpen; render(); });
  if (state.distFeedOpen) {
    y += 10;
    body.appendChild(txt(X + 2, y, "Pre-filtered to " + d.name + " — record type & Refine (F) still apply.", 10.5, "#bbb"));
    y += 16;
    if (shown.length === 0) {
      var e1 = txt(X + W / 2, y + 18, "No posts match the current filter.", 13, "#999"); e1.setAttribute("text-anchor", "middle"); body.appendChild(e1);
      y += 44;
    }
    shown.forEach(function (p) {
      var card = buildCard(p, { hideJur: true, hideDistrict: true }); // riding implied → drop both tags
      card.setAttribute("transform", "translate(" + X + "," + y + ")");
      body.appendChild(card);
      y += card._h + 14;
    });
  } else { y += 12; }

  setViewScroll("district", y);
}

// ---- PROFILE (public profile of a representative — the MLA Rae Nguyen) -----
function buildProfile() {
  var body = $("vProfBody");
  while (body.firstChild) body.removeChild(body.firstChild);
  var X = 30, W = 370, p = PROFILE, y = 124;

  body.appendChild(txt(X, y + 6, "Public profile", 11, "#bbb"));

  // identity header
  var av = document.createElementNS(SVG_NS, "circle");
  av.setAttribute("cx", X + 38); av.setAttribute("cy", y + 60); av.setAttribute("r", 34);
  av.setAttribute("fill", "#e8e8e8"); av.setAttribute("stroke", "#ccc"); body.appendChild(av);
  var ini = (p.name.split(" ").map(function (s) { return s[0]; }).join("")).slice(0, 2).toUpperCase();
  var it = txt(X + 38, y + 68, ini, 22, "#888"); it.setAttribute("text-anchor", "middle"); body.appendChild(it);

  var nm = txt(X + 90, y + 44, p.name, 19, "#222"); nm.setAttribute("font-weight", "bold"); body.appendChild(nm);
  body.appendChild(txt(X + 90, y + 64, "@" + p.handle, 12.5, "#999"));
  // role reads "<seat> · <riding>" — deep-link + underline the riding segment to the District view
  var roleParts = p.role.split(" · "), distSeg = roleParts[roleParts.length - 1];
  if (roleParts.length > 1 && DISTRICT.name === distSeg) {
    var prefix = p.role.slice(0, p.role.length - distSeg.length);
    body.appendChild(txtSeg(X + 90, y + 84, 12.5, "#555", [[prefix, false], [distSeg, true]]));
    var preW = prefix.length * 12.5 * 0.54, segW = distSeg.length * 12.5 * 0.54;
    var rdg = document.createElementNS(SVG_NS, "g"); rdg.style.cursor = "pointer";
    clickRect(rdg, X + 90 + preW - 2, y + 72, segW + 4, 17, go("district")); body.appendChild(rdg);
  } else {
    body.appendChild(txt(X + 90, y + 84, p.role, 12.5, "#555"));
  }
  // verification badge: Official (tier 3, MLA / gov) or Residency Verified (tier 2)
  if (p.tier >= 2) {
    var badge = p.tier === 3 ? "Official" : "Residency Verified";
    var bw = p.tier === 3 ? 96 : 132;
    body.appendChild(rect(X + 90, y + 94, bw, 22, 11, "#333"));
    body.appendChild(icon("#ic-shield", X + 98, y + 97, 15, "#fff"));
    body.appendChild(txt(X + 118, y + 109, badge, 11, "#fff"));
  }
  y += 140;

  // activity stats
  var tw = (W - 16) / 3;
  p.stats.forEach(function (s, i) {
    var sx = X + i * (tw + 8);
    body.appendChild(rect(sx, y, tw, 64, 10, "#fafafa", "#eee"));
    var n = txt(sx + tw / 2, y + 30, fmtN(s.n), 20, "#333"); n.setAttribute("text-anchor", "middle"); n.setAttribute("font-weight", "bold"); body.appendChild(n);
    var l = txt(sx + tw / 2, y + 50, s.label, 10.5, "#999"); l.setAttribute("text-anchor", "middle"); body.appendChild(l);
  });
  y += 84;

  // posts (link-out → Feed filtered by this author; representative target → Feed)
  var pg = document.createElementNS(SVG_NS, "g"); pg.style.cursor = "pointer";
  pg.appendChild(rect(X, y, W, 40, 8, "#f7f7f7", "#e2e2e2"));
  pg.appendChild(icon("#ic-list", X + 12, y + 11, 18, "#333"));
  pg.appendChild(txt(X + 40, y + 25, "View their posts in Feed", 14, "#333"));
  pg.appendChild(icon("#ic-chevron-right", X + W - 28, y + 11, 16, "#777"));
  clickRect(pg, X, y, W, 40, go("feed"));
  body.appendChild(pg);
  y += 56;

  setViewScroll("profile", y);
}

// ---- POST (one post + threaded comments to depth 3) -----------------------
function countComments(nodes) {
  return nodes.reduce(function (a, n) { return a + 1 + countComments(n.replies || []); }, 0);
}
// toggle the viewer's agree/disagree on a target (post or comment); mutually exclusive
function toggleReact(node, dir) {
  if (node._my === dir) { node[dir]--; node._my = null; }
  else { if (node._my) node[node._my]--; node[dir]++; node._my = dir; }
  render();
}
// a reaction click only counts for a signed-in member; logged-out → auth gateway
function reactClick(node, dir) {
  if (!state.loggedIn) { state.authView = "choose"; render(); return; }
  toggleReact(node, dir);
}
// one reaction pill (✓ agree / ✗ disagree). Shared by the post, comment threads, and
// feed/jurisdiction/district cards — every reaction in the app routes through here, so the
// login gate and toggle behave identically everywhere. `scale` maps the raw count to its
// shown value (cards thin by the Verified filter via scaleSocial; the post shows it raw).
function reactBtn(parent, node, dir, x, y, scale) {
  scale = scale || function (n) { return n; };
  var sym = dir === "up" ? "✓ " : "✗ ";
  var active = node._my === dir;
  var col = active ? "#333" : (dir === "up" ? "#666" : "#999");
  var g = document.createElementNS(SVG_NS, "g");
  var t = txt(x, y, sym + fmtN(scale(node[dir])), 13, col); if (active) t.setAttribute("font-weight", "bold"); g.appendChild(t);
  clickRect(g, x - 4, y - 14, 54, 20, function (e) { if (e) e.stopPropagation(); reactClick(node, dir); });
  parent.appendChild(g);
}
function replyStub(parent, x, y, enabled) {
  if (!enabled) { parent.appendChild(txt(x, y, "↳ max depth", 12, "#ccc")); return; }
  var g = document.createElementNS(SVG_NS, "g"); g.style.cursor = "pointer";
  g.appendChild(txt(x, y, "↳ Reply", 12, "#999"));
  clickRect(g, x - 4, y - 13, 60, 19, function (e) { if (e) e.stopPropagation(); /* NOTE(nav): compose a reply (comment create) — deferred */ });
  parent.appendChild(g);
}
function buildThread(parent, nodes, depth, y) {
  var X0 = 30, W0 = 370;
  nodes.forEach(function (node) {
    var indent = (depth - 1) * 20, x = X0 + indent, w = W0 - indent;
    var av = document.createElementNS(SVG_NS, "circle");
    av.setAttribute("cx", x + 11); av.setAttribute("cy", y + 9); av.setAttribute("r", 11);
    av.setAttribute("fill", "#eee"); av.setAttribute("stroke", "#ddd"); parent.appendChild(av);
    var ini = (node.author.split(" ").map(function (s) { return s[0]; }).join("")).slice(0, 2).toUpperCase();
    var it = txt(x + 11, y + 13, ini, 9, "#888"); it.setAttribute("text-anchor", "middle"); parent.appendChild(it);
    var nm = txt(x + 28, y + 6, node.author, 12.5, "#333"); nm.setAttribute("font-weight", "bold"); parent.appendChild(nm);
    var hd = txt(x + w, y + 6, "@" + node.handle, 10.5, "#aaa"); hd.setAttribute("text-anchor", "end"); parent.appendChild(hd);
    var yy = y + 24;
    node.body.forEach(function (line) { parent.appendChild(txt(x + 28, yy, line, 12, "#555")); yy += 16; });
    reactBtn(parent, node, "up", x + 28, yy + 8);
    reactBtn(parent, node, "down", x + 82, yy + 8);
    replyStub(parent, x + 140, yy + 8, depth < COMMENT_MAX_DEPTH);
    yy += 24;
    var ny = yy;
    if (node.replies && node.replies.length && depth < COMMENT_MAX_DEPTH) ny = buildThread(parent, node.replies, depth + 1, yy);
    y = ny + 10;
  });
  return y;
}
function buildPost() {
  var body = $("vPostBody");
  while (body.firstChild) body.removeChild(body.firstChild);
  var X = 30, W = 370, p = POST, y = 118;

  // author row
  var av = document.createElementNS(SVG_NS, "circle");
  av.setAttribute("cx", X + 14); av.setAttribute("cy", y + 16); av.setAttribute("r", 14);
  av.setAttribute("fill", "#e8e8e8"); av.setAttribute("stroke", "#ccc"); body.appendChild(av);
  var ini = (p.author.split(" ").map(function (s) { return s[0]; }).join("")).slice(0, 2).toUpperCase();
  var it = txt(X + 14, y + 20, ini, 11, "#777"); it.setAttribute("text-anchor", "middle"); body.appendChild(it);
  var nm = txt(X + 38, y + 12, p.author, 14, "#333"); nm.setAttribute("font-weight", "bold"); body.appendChild(nm);
  body.appendChild(txt(X + 38, y + 28, "@" + p.handle, 11.5, "#999"));
  var aHit = document.createElementNS(SVG_NS, "g"); clickRect(aHit, X, y, 190, 34, go("profile")); body.appendChild(aHit);
  if (p.tier > 0) {
    body.appendChild(icon("#ic-shield", X + W - 92, y + 3, 14, "#666"));
    var tl = txt(X + W, y + 14, tierLabel(p.tier), 11.5, "#666"); tl.setAttribute("text-anchor", "end"); body.appendChild(tl);
  }
  body.appendChild(scopeTagLink(p.jur, p.district || "", X + W, y + 30));
  y += 48;

  // title + full body
  var ti = txt(X, y + 16, p.title, 17, "#222"); ti.setAttribute("font-weight", "bold"); body.appendChild(ti);
  y += 30;
  p.body.forEach(function (line) { body.appendChild(txt(X, y + 14, line, 13, "#555")); y += 18; });
  y += 10;

  // post reaction bar
  reactBtn(body, p, "up", X, y);
  reactBtn(body, p, "down", X + 66, y);
  var nC = countComments(COMMENTS);
  body.appendChild(icon("#ic-message", X + W - 64, y - 13, 15, "#777"));
  var cc = txt(X + W, y, fmtN(nC), 13, "#777"); cc.setAttribute("text-anchor", "end"); body.appendChild(cc);
  y += 22;

  // divider + comments header
  var ln = document.createElementNS(SVG_NS, "line");
  ln.setAttribute("x1", X); ln.setAttribute("y1", y); ln.setAttribute("x2", X + W); ln.setAttribute("y2", y);
  ln.setAttribute("stroke", "#eee"); body.appendChild(ln);
  y += 24;
  var ch = txt(X, y, "Comments (" + nC + ")", 13.5, "#333"); ch.setAttribute("font-weight", "bold"); body.appendChild(ch);
  y += 18;

  // thread
  y = buildThread(body, COMMENTS, 1, y);
  y += 16;

  setViewScroll("post", y);
}

// ============================================================================
// VIEWS REGISTRY — the page table. Each entry: the outer group to show (el),
// the scrolled body (body), the title shown in the header, the builder, and a
// live scroll max. render() builds VIEWS[state.view], shows its el, and the one
// wheel listener clamps state.scroll to VIEWS[state.view].max.
// ============================================================================
var VIEWS = {
  feed:         { el: "vFeed", body: "vFeedBody", title: "Feed",         build: buildFeed,         max: 0 },
  jurisdiction: { el: "vJur",  body: "vJurBody",  title: "Jurisdiction", build: buildJurisdiction, max: 0 },
  district:     { el: "vDist", body: "vDistBody", title: "District",     build: buildDistrict,     max: 0 },
  profile:      { el: "vProf", body: "vProfBody", title: "Profile",      build: buildProfile,      max: 0 },
  post:         { el: "vPost", body: "vPostBody", title: "Post",         build: buildPost,         max: 0 }
};
var VIEW_ORDER = ["feed", "jurisdiction", "district", "profile", "post"];

// bottom whitespace so the FAB never covers the last line at full scroll — applied
// uniformly here (drift fix: feed & post used to lack it).
var FOOTER_PAD = 80;
function setViewScroll(viewKey, y) {
  var max = Math.max(0, y + FOOTER_PAD - 885 + 8);
  VIEWS[viewKey].max = max;
  state.scroll = clamp(state.scroll, 0, max);
  $(VIEWS[viewKey].body).setAttribute("transform", "translate(0," + (-state.scroll) + ")");
}

// dynamic per-view caption shown in the left margin (replaces 5× body callouts)
var VIEW_CAP = {
  feed:         ["Feed — unified, filtered list", "tap a card → Post; author → Profile"],
  jurisdiction: ["Jurisdiction view (G flips Glob/AB)", "leader → Profile; riding → District"],
  district:     ["District view (one riding)", "leader → Profile; cards → Post"],
  profile:      ["Profile view (public)", "View posts → Feed"],
  post:         ["Post + comment thread (depth 3)", "✓/✗ react; ↳ Reply (stub)"]
};

// ---- main render ----------------------------------------------------------
function render() {
  // My Districts requires a residency-verified account — never let it stick otherwise
  if (state.kyc < 2) state.myDistricts = false;

  var view = state.view;
  // 1) build the active view, 2) show only its group
  VIEWS[view].build();
  VIEW_ORDER.forEach(function (k) { show($(VIEWS[k].el), k === view); });

  // header title + dynamic caption
  $("appTitle").textContent = "OurSay · Mobile — " + VIEWS[view].title;
  $("annoViewCap1").textContent = VIEW_CAP[view][0];
  $("annoViewCap2").textContent = VIEW_CAP[view][1];

  // auth state + its callout
  show($("loginGlyph"), !state.loggedIn);
  show($("profileGlyph"), state.loggedIn);
  $("authCircle").setAttribute("fill", state.loggedIn ? "#333" : "#ffffff");
  $("annoLoginA").textContent = state.loggedIn ? "Signed in (avatar shown)" : "Logged out";
  $("annoLoginB").textContent = state.loggedIn ? "tap → profile (L to toggle)" : "tap → register / log in (L)";

  // selector pill: Jurisdiction/District views name their own jurisdiction (tracks the page,
  // not the feed filter); every other view uses the unified-feed label.
  if (view === "jurisdiction") $("curJur").textContent = state.jur;
  else if (view === "district") $("curJur").textContent = DISTRICT.jur;
  else $("curJur").textContent = pillLabel();

  // dropdown
  if (state.dropdownOpen) buildDropdown();
  show($("dropdown"), state.dropdownOpen);
  show($("modal"), state.modalOpen);

  // feed filter dropdown (left button)
  if (state.filterOpen) buildFilter();
  show($("filterDropdown"), state.filterOpen);

  // logged-out auth flow: chooser → register form → verify (OTP + passkey) · or → login
  var inAuth = !state.loggedIn;
  show($("authModal"),     inAuth && state.authView === "choose");
  show($("registerModal"), inAuth && state.authView === "register");
  show($("verifyModal"),   inAuth && state.authView === "verify");
  show($("loginModal"),    inAuth && state.authView === "login");
  if (inAuth && state.authView === "login") buildLoginInner();

  // spotlight result: if Alberta is already subscribed, offer Delete instead of Join
  var hasAlberta = state.subs.some(function (s) { return s.name === "Alberta"; });
  var act = $("albertaAction");
  act.textContent = hasAlberta ? "Delete ✕" : "Join ›";
  act.setAttribute("fill", hasAlberta ? "#c0392b" : "#999");

  // profile modal (only meaningful while logged in)
  show($("profileModal"), state.profileOpen && state.loggedIn);
  $("kycBadgeText").textContent = KYC_TIERS[state.kyc];
  $("kycBadge").querySelector("rect").setAttribute("fill", state.kyc === 0 ? "#f2f2f2" : "#333");
  $("kycBadgeText").setAttribute("fill", state.kyc === 0 ? "#555" : "#fff");
  $("kycShield").setAttribute("stroke", state.kyc === 0 ? "#666" : "#fff");
  $("deviceLabel").textContent = "Devices & passkeys (" + state.deviceCount + ")";
  var more = state.deviceCount - 2;
  var moreEl = $("deviceMore");
  moreEl.textContent = "+" + more + " more";
  show(moreEl, more > 0);

  // theme preference toggle (button only — no app-wide repaint)
  var dark = state.theme === "Dark";
  $("themeValue").textContent = state.theme;
  $("themeIcon").setAttribute("href", dark ? "#ic-moon" : "#ic-sun");
  $("themeIcon").setAttributeNS(XLINK, "href", dark ? "#ic-moon" : "#ic-sun");

  // compose flow: where → type → compose (logged-in only)
  show($("whereModal"),   state.loggedIn && state.composeStep === "where");
  show($("typeModal"),    state.loggedIn && state.composeStep === "type");
  show($("composeModal"), state.loggedIn && state.composeStep === "compose");
  if (state.composeStep === "where") buildWhere();
  if (state.composeStep === "type") buildType();
  if (state.composeStep === "compose") {
    var jn = state.composeJur || "Global", sub = subByName(jn), rm = rootMeta(state.composeType);
    $("composeJurName").textContent = jn;
    $("composeJurIcon").setAttribute("href", sub ? sub.icon : "#ic-globe");
    $("composeJurIcon").setAttributeNS(XLINK, "href", sub ? sub.icon : "#ic-globe");
    $("composeTypeLabel").textContent = rm.label;
    $("composeTypeIcon").setAttribute("href", rm.icon);
    $("composeTypeIcon").setAttributeNS(XLINK, "href", rm.icon);
    show($("composeChangeBtn"), rootsFor(jn).length > 1);
    buildComposeEditor();
    if (state.composeJurOpen) buildComposeJurMenu();
    show($("composeJurMenu"), state.composeJurOpen);
  }

  // FAB icon + callout depend on the active view (compose on Feed, "go home" elsewhere)
  var onFeed = view === "feed";
  show($("fabCompose"), onFeed);
  show($("fabFeed"), !onFeed);
  $("annoFabA").textContent = onFeed ? "On Feed" : "On " + VIEWS[view].title;
  $("annoFabB").textContent = onFeed ? "tap → compose a post (quill)" : "tap → go to Feed (newspaper)";

  // labels: chrome shown unless the full-screen profile sheet covers it; overlay callouts
  // only while that overlay is open; include-filter callout only when checkboxes are shown
  show($("anno-chrome"), state.labelsOn && !state.profileOpen);
  show($("anno-dropdown"), state.labelsOn && state.dropdownOpen);
  show($("anno-dd-filter"), state.labelsOn && state.dropdownOpen && state.subs.length > 1);
  show($("anno-filter"), state.labelsOn && state.filterOpen);
  // record-types callout only on feed views; refine callout slides up by the dropped section's height
  show($("anno-filter-types"), viewHasFeed());
  $("anno-filter-refine").setAttribute("transform", viewHasFeed() ? "translate(0,0)" : "translate(0," + (-(24 + 5 * FROW_H + 8)) + ")");
  show($("anno-modal"), state.labelsOn && state.modalOpen);
  show($("anno-auth"), state.labelsOn && !!state.authView && !state.loggedIn);
  show($("anno-profile"), state.labelsOn && state.profileOpen && state.loggedIn);
}

// ---- wiring ---------------------------------------------------------------
$("filterBtn").addEventListener("click", function () { state.filterOpen = !state.filterOpen; state.dropdownOpen = false; render(); });
$("selectorBtn").addEventListener("click", function () { state.dropdownOpen = !state.dropdownOpen; state.filterOpen = false; render(); });

// ONE wheel listener for every view — scrolls the active view's body, clamped to its max.
// (No scroll while an overlay is open.)
$("content").addEventListener("wheel", function (e) {
  if (state.filterOpen || state.dropdownOpen || state.modalOpen || state.composeStep || state.profileOpen || state.authView) return;
  e.preventDefault();
  var v = VIEWS[state.view];
  state.scroll = clamp(state.scroll + e.deltaY, 0, v.max);
  $(v.body).setAttribute("transform", "translate(0," + (-state.scroll) + ")");
}, { passive: false });

$("authBtn").addEventListener("click", onAuthClick);
$("fab").addEventListener("click", onFabClick);
$("modalBackdrop").addEventListener("click", closeOverlays);
$("filterBackdrop").addEventListener("click", closeOverlays);
$("ddBackdrop").addEventListener("click", closeOverlays);
$("modalCloseBtn").addEventListener("click", function (e) { e.stopPropagation(); closeOverlays(); });
$("profileCloseBtn").addEventListener("click", function (e) { e.stopPropagation(); closeOverlays(); });
$("authCloseBtn").addEventListener("click", function (e) { e.stopPropagation(); closeOverlays(); });
$("resultAlberta").addEventListener("click", function () {
  var i = state.subs.findIndex(function (s) { return s.name === "Alberta"; });
  if (i === -1) {
    state.subs.push({ name: "Alberta", icon: "#ic-building", included: true });
  } else {
    state.subs.splice(i, 1);
    if (!state.subs.some(function (s) { return s.included; })) state.subs[0].included = true;
  }
  state.modalOpen = false;
  state.dropdownOpen = true;
  render();
});

// chooser modal: pick register or login (logged-out only)
$("authBackdrop").addEventListener("click", closeOverlays);
$("registerBtn").addEventListener("click", function (e) { e.stopPropagation(); state.authView = "register"; render(); });
$("loginBtn").addEventListener("click", function (e) {
  e.stopPropagation();
  if (!state.otpAllowed) { signIn(); }
  else { state.authView = "login"; state.loginVerified = false; render(); }
});
$("recoverBtn").addEventListener("click", function (e) { e.stopPropagation(); state.authView = "register"; render(); });

// register form → verify page
$("registerBackdrop").addEventListener("click", closeOverlays);
$("registerCloseBtn").addEventListener("click", function (e) { e.stopPropagation(); closeOverlays(); });
$("regSubmitBtn").addEventListener("click", function (e) { e.stopPropagation(); state.authView = "verify"; render(); });

// verify page → register passkey → in
$("verifyBackdrop").addEventListener("click", closeOverlays);
$("verifyCloseBtn").addEventListener("click", function (e) { e.stopPropagation(); closeOverlays(); });
$("regPasskeyBtn").addEventListener("click", function (e) { e.stopPropagation(); signIn(); });
$("verifyResendBtn").addEventListener("click", function (e) { e.stopPropagation(); /* resend OTP — deferred */ });

// login modal (returning user)
$("loginBackdrop").addEventListener("click", closeOverlays);
$("loginCloseBtn").addEventListener("click", function (e) { e.stopPropagation(); closeOverlays(); });

// compose flow
$("whereBackdrop").addEventListener("click", closeOverlays);
$("whereCloseBtn").addEventListener("click", function (e) { e.stopPropagation(); closeOverlays(); });
$("typeBackdrop").addEventListener("click", closeOverlays);
$("typeCloseBtn").addEventListener("click", function (e) { e.stopPropagation(); closeOverlays(); });
$("composeBackdrop").addEventListener("click", closeOverlays);
$("composeCloseBtn").addEventListener("click", function (e) { e.stopPropagation(); closeOverlays(); });
$("composeJurBtn").addEventListener("click", function (e) { e.stopPropagation(); state.composeJurOpen = !state.composeJurOpen; render(); });
$("composeChangeBtn").addEventListener("click", function (e) { e.stopPropagation(); state.composeStep = "type"; state.composeJurOpen = false; render(); });

// profile modal actions
$("profileBackdrop").addEventListener("click", closeOverlays);
$("logoutBtn").addEventListener("click", logout);
$("validateBtn").addEventListener("click", function (e) {
  e.stopPropagation();
  state.kyc = (state.kyc + 1) % KYC_TIERS.length;
  render();
});
$("addDeviceBtn").addEventListener("click", function (e) { e.stopPropagation(); state.deviceCount++; render(); });
$("addDeviceEmailBtn").addEventListener("click", function (e) { e.stopPropagation(); state.otpAllowed = true; render(); });

// direct account-settings items (each its own destination — deferred no-ops)
["editProfileBtn", "changeAddrBtn", "privacySettingsBtn", "jurisdictionsBtn", "termsBtn", "privacyBtn"].forEach(function (id) {
  $(id).addEventListener("click", function (e) { e.stopPropagation(); /* deferred */ });
});

// theme: live toggle (Light ↔ Dark) — preference only
$("themeBtn").addEventListener("click", function (e) {
  e.stopPropagation();
  state.theme = (state.theme === "Light") ? "Dark" : "Light";
  render();
});

document.addEventListener("keydown", function (e) {
  switch (e.key) {
    case "l": case "L":
      state.loggedIn = !state.loggedIn;
      if (!state.loggedIn) state.profileOpen = false;
      render();
      break;
    case "v": case "V": state.labelsOn = !state.labelsOn; render(); break;
    case "j": case "J": state.dropdownOpen = !state.dropdownOpen; state.filterOpen = false; render(); break;
    case "f": case "F": state.filterOpen = !state.filterOpen; state.dropdownOpen = false; render(); break;
    case "a": case "A": openModal(); break;
    case "o": case "O": state.otpAllowed = !state.otpAllowed; state.loginVerified = false; render(); break;
    case "p": case "P": // demo shortcut: cycle the router through the five views
      nav(VIEW_ORDER[(VIEW_ORDER.indexOf(state.view) + 1) % VIEW_ORDER.length]);
      break;
    case "g": case "G": // flip which jurisdiction the Jurisdiction view shows (no-op elsewhere)
      if (state.view === "jurisdiction") { state.jur = (state.jur === "Alberta") ? "Global" : "Alberta"; state.scroll = 0; render(); }
      break;
    case "Escape": closeOverlays(); break;
  }
});

render();
